@page "/catalog"
@using sv_8db955293d7c4b74b8ce92820c40c415.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    @* Sidebar *@
    <div class="col-lg-3 mb-3">
        <CatalogFilters Categories="_categories" OnFilterApplied="HandleFilterApplied" />
    </div>

    @* Main content *@
    <div class="col-lg-9">
        @if (_error is not null)
        {
            <div class="alert alert-danger">
                <strong>Error:</strong> @_error
                <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetrySearch">Retry</button>
            </div>
        }
        else if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading products...</span>
                </div>
                <span class="ms-2">Loading products...</span>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="@_result.TotalCount"
                            Page="@_result.Page"
                            PageSize="@_result.PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="@_result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="@_result.Page"
                               TotalCount="@_result.TotalCount"
                               PageSize="@_result.PageSize"
                               OnPageChanged="HandlePageChanged" />
        }
    </div>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;
    private bool _loading = true;
    private string? _error;
    private PagedResult<Product> _result = new([], 0, 1, PageSize);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            await Task.WhenAll(categoriesTask, productsTask);

            _categories = categoriesTask.Result;
            _result = productsTask.Result;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }

    private async Task RetrySearch()
    {
        await SearchAsync();
    }
}

